import React from "react";

const Header = ({ siteName = "IntellMeet", role, logout, view, setView }) => {
  return (
    <header style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "12px 20px", borderBottom: "1px solid #eee" }}>
      <div style={{ flex: 1 }} />

      <div style={{ textAlign: "center", flex: 1 }}>
        <h1 style={{ margin: 0 }}>{siteName}</h1>
      </div>

      <div style={{ display: "flex", gap: 8, alignItems: "center", justifyContent: "flex-end", flex: 1 }}>
        {role === "admin" ? (
          <button onClick={() => setView("dashboard")}>Admin Dashboard</button>
        ) : (
          <button onClick={() => setView("products")}>Products</button>
        )}

        <button onClick={logout}>Logout</button>
      </div>
    </header>
  );
};

export default Header;
